import React from 'react';

const ContactoPage = () => {
  const images = [
    {
      src: '/media/contactoPage/LP.png',
      alt: 'Entrada UCB',
      link: 'https://www.ucb.edu.bo/',
      text: 'Bienvenido a la Universidad Católica Boliviana',
    },
    {
      src: '/media/contactoPage/SIS - H.png',
      alt: 'Logo SIS',
      link: 'https://www.ucb.edu.bo/contacto',
      text: 'Sistema de Información y Servicios',
    },
    {
      src: '/media/contactoPage/IIE - H.png',
      alt: 'Equipo ADM',
      link: 'https://www.ucb.edu.bo/nosotros',
      text: 'Instituto de Investigaciones y Estudios',
    },
  ];

  return (
    <main style={styles.page}>
      <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>
      <div style={styles.imagesContainer}>
        {images.map(({ src, alt, link, text }, idx) => (
          <a
            key={idx}
            href={link}
            target="_blank"
            rel="noopener noreferrer"
            style={styles.linkContainer}
          >
            <img src={src} alt={alt} style={styles.image} />
            <div style={styles.textContainer}>
              <p style={styles.text}>{text}</p>
            </div>
          </a>
        ))}
      </div>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F8F0E3',
    minHeight: '100vh',
    padding: '3rem 1rem',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    color: '#052018',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '3rem',
    textAlign: 'center',
  },
  imagesContainer: {
    display: 'flex',
    flexDirection: 'column',
    gap: '2rem',
    maxWidth: 960,
    margin: '0 auto',
  },
  linkContainer: {
    display: 'flex',
    alignItems: 'center',
    textDecoration: 'none',
    color: '#052018',
    gap: '1.5rem',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    padding: '1rem',
    backgroundColor: 'white',
    transition: 'transform 0.3s ease',
    cursor: 'pointer',
  },
  image: {
    width: 120,
    height: 120,
    objectFit: 'cover',
    borderRadius: 12,
    flexShrink: 0,
  },
  textContainer: {
    flex: 1,
  },
  text: {
    fontSize: '1.1rem',
    fontWeight: '600',
  },
};

export default ContactoPage;
